#include<bits/stdc++.h>
using namespace std;
int in[200005], out[200005],v[200005];
map<int, int> m[200005];
vector<int> e[200005];
bool dfs(int x) {
	v[x] = 1;
	for (int i = 0; i < e[x].size(); i++) {
		int y = e[x][i];
        if(v[y] == 1) return 0;  
        if(v[y] == 0) if(!dfs(y)) return 0;
	}
    v[x]=2;
	return 1;
}
int main() {
	int n, mm, k = 0;
	long long ans = 1;
	cin >> n >> mm;
	for (int i = 1; i <= mm; i++) {
		int x, y;
		cin >> x >> y;
		if (m[x][y]) continue;
		if (in[y] > 0 && out[x] > 0) {
			cout << 0;
			return 0;
		}
		m[x][y] = 1;
		in[y]++;
		out[x]++;
		e[x].push_back(y);
		k++;
	}
	for (int i = 1; i <= n; i++) {
		if (out[i] > 0 && v[i] == 0) {
            if (!dfs(i)) {
                cout << 0 << "\n";
                return 0;
            }
        }
	}
	for (int i = 1; i <= n; i++) {
		if (v[i] == 0 && (in[i] > 0 || out[i] > 0)) {
			cout << 0 << "\n";
			return 0;
		}
	}
	for (int i = 1; i <= n - k; i++) {
		ans *= (long long)i;
		ans %= (long long)(1e9 + 7);
	}
	cout << ans;
	return 0;
}
